// SPDX-License-Identifier: GPL-2.0
/*
 * SpacemiT K1 USB 2.0 PHY driver
 *
 * Copyright (C) 2025 SpacemiT
 */

#include <linux/bitfield.h>
#include <linux/clk.h>
#include <linux/iopoll.h>
#include <linux/kernel.h>
#include <linux/module.h>
#include <linux/phy/phy.h>
#include <linux/platform_device.h>
#include <linux/reset.h>
#include <linux/usb/of.h>

#define PHY_TIMEOUT			500000
#define POLL_DELAY			500

/* USB 2.0 PHY register offsets */
#define USB2_PHY_CTRL0			0x00
#define USB2_PHY_CTRL1			0x04
#define USB2_PHY_STATUS		0x08
#define USB2_PHY_CLK_CTRL		0x0c
#define USB2_PHY_TUNE			0x10

/* CTRL0 register bits */
#define PHY_SOFTRST			BIT(0)
#define PHY_PLL_PWR_DOWN		BIT(1)
#define PHY_REFCLK_EN			BIT(2)
#define PHY_CLK_EN			BIT(3)

/* CTRL1 register bits */
#define PHY_LS_KEEPALIVE_EN		BIT(0)
#define PHY_OTG_DISABLE			BIT(1)
#define PHY_HOST_MODE			BIT(2)
#define PHY_DEVICE_MODE			BIT(3)

/* STATUS register bits */
#define PHY_PLL_LOCK			BIT(0)
#define PHY_CLK_READY			BIT(1)

/* CLK_CTRL register bits */
#define PHY_125M_CLK_EN			BIT(0)
#define PHY_60M_CLK_EN			BIT(1)
#define PHY_48M_CLK_EN			BIT(2)

struct k1_usb2_phy {
	struct device *dev;
	void __iomem *regs;
	struct clk *clk;
	struct reset_control *rst;
	enum phy_mode mode;
};

static void k1_usb2_phy_set_mode(struct k1_usb2_phy *priv,
				 enum phy_mode mode)
{
	u32 val;

	val = readl(priv->regs + USB2_PHY_CTRL1);
	val &= ~(PHY_HOST_MODE | PHY_DEVICE_MODE);
	val &= ~PHY_LS_KEEPALIVE_EN;

	switch (mode) {
	case PHY_MODE_USB_HOST:
		val |= PHY_HOST_MODE;
		val |= PHY_LS_KEEPALIVE_EN;
		break;
	case PHY_MODE_USB_DEVICE:
		val |= PHY_DEVICE_MODE;
		break;
	case PHY_MODE_USB_OTG:
		val &= ~PHY_OTG_DISABLE;
		break;
	default:
		return;
	}

	writel(val, priv->regs + USB2_PHY_CTRL1);
}

static int k1_usb2_phy_init(struct phy *phy)
{
	struct k1_usb2_phy *priv = phy_get_drvdata(phy);
	u32 val;
	int ret;

	ret = clk_prepare_enable(priv->clk);
	if (ret)
		return ret;

	/* De-assert software reset */
	val = readl(priv->regs + USB2_PHY_CTRL0);
	val &= ~PHY_SOFTRST;
	writel(val, priv->regs + USB2_PHY_CTRL0);

	/* Enable reference clock */
	val |= PHY_REFCLK_EN;
	writel(val, priv->regs + USB2_PHY_CTRL0);

	/* Power up PLL */
	val &= ~PHY_PLL_PWR_DOWN;
	writel(val, priv->regs + USB2_PHY_CTRL0);

	/* Wait for PLL lock */
	ret = readl_poll_timeout(priv->regs + USB2_PHY_STATUS, val,
				 val & PHY_PLL_LOCK,
				 POLL_DELAY, PHY_TIMEOUT);
	if (ret) {
		dev_err(priv->dev, "PHY PLL failed to lock\n");
		clk_disable_unprepare(priv->clk);
		return ret;
	}

	/* Enable PHY clock */
	val = readl(priv->regs + USB2_PHY_CTRL0);
	val |= PHY_CLK_EN;
	writel(val, priv->regs + USB2_PHY_CTRL0);

	/* Enable output clocks */
	val = readl(priv->regs + USB2_PHY_CLK_CTRL);
	val |= PHY_48M_CLK_EN | PHY_60M_CLK_EN | PHY_125M_CLK_EN;
	writel(val, priv->regs + USB2_PHY_CLK_CTRL);

	k1_usb2_phy_set_mode(priv, priv->mode);

	return 0;
}

static int k1_usb2_phy_exit(struct phy *phy)
{
	struct k1_usb2_phy *priv = phy_get_drvdata(phy);
	u32 val;

	/* Disable output clocks */
	val = readl(priv->regs + USB2_PHY_CLK_CTRL);
	val &= ~(PHY_48M_CLK_EN | PHY_60M_CLK_EN | PHY_125M_CLK_EN);
	writel(val, priv->regs + USB2_PHY_CLK_CTRL);

	/* Power down PLL */
	val = readl(priv->regs + USB2_PHY_CTRL0);
	val |= PHY_PLL_PWR_DOWN;
	writel(val, priv->regs + USB2_PHY_CTRL0);

	clk_disable_unprepare(priv->clk);

	return 0;
}

static int k1_usb2_phy_power_on(struct phy *phy)
{
	struct k1_usb2_phy *priv = phy_get_drvdata(phy);
	u32 val;

	val = readl(priv->regs + USB2_PHY_CTRL0);
	val &= ~PHY_PLL_PWR_DOWN;
	val |= PHY_REFCLK_EN | PHY_CLK_EN;
	writel(val, priv->regs + USB2_PHY_CTRL0);

	return 0;
}

static int k1_usb2_phy_power_off(struct phy *phy)
{
	struct k1_usb2_phy *priv = phy_get_drvdata(phy);
	u32 val;

	val = readl(priv->regs + USB2_PHY_CTRL0);
	val |= PHY_PLL_PWR_DOWN;
	writel(val, priv->regs + USB2_PHY_CTRL0);

	return 0;
}

static int k1_usb2_phy_set_mode(struct phy *phy, enum phy_mode mode,
				int submode)
{
	struct k1_usb2_phy *priv = phy_get_drvdata(phy);

	switch (mode) {
	case PHY_MODE_USB_HOST:
	case PHY_MODE_USB_DEVICE:
	case PHY_MODE_USB_OTG:
		break;
	default:
		return -EINVAL;
	}

	priv->mode = mode;
	k1_usb2_phy_set_mode(priv, mode);

	return 0;
}

static const struct phy_ops k1_usb2_phy_ops = {
	.init		= k1_usb2_phy_init,
	.exit		= k1_usb2_phy_exit,
	.power_on	= k1_usb2_phy_power_on,
	.power_off	= k1_usb2_phy_power_off,
	.set_mode	= k1_usb2_phy_set_mode,
	.owner		= THIS_MODULE,
};

static int k1_usb2_phy_probe(struct platform_device *pdev)
{
	struct device *dev = &pdev->dev;
	struct phy_provider *phy_provider;
	struct k1_usb2_phy *priv;
	struct phy *phy;

	priv = devm_kzalloc(dev, sizeof(*priv), GFP_KERNEL);
	if (!priv)
		return -ENOMEM;

	priv->dev = dev;
	priv->mode = PHY_MODE_USB_HOST;

	priv->regs = devm_platform_ioremap_resource(pdev, 0);
	if (IS_ERR(priv->regs))
		return dev_err_probe(dev, PTR_ERR(priv->regs),
				     "failed to map PHY registers\n");

	priv->clk = devm_clk_get(dev, NULL);
	if (IS_ERR(priv->clk))
		return dev_err_probe(dev, PTR_ERR(priv->clk),
				     "failed to get PHY clock\n");

	priv->rst = devm_reset_control_get_optional(dev, NULL);
	if (IS_ERR(priv->rst))
		return dev_err_probe(dev, PTR_ERR(priv->rst),
				     "failed to get PHY reset\n");

	phy = devm_phy_create(dev, NULL, &k1_usb2_phy_ops);
	if (IS_ERR(phy))
		return dev_err_probe(dev, PTR_ERR(phy),
				     "failed to create PHY\n");

	phy_set_drvdata(phy, priv);

	phy_provider = devm_of_phy_provider_register(dev, of_phy_simple_xlate);
	if (IS_ERR(phy_provider))
		return dev_err_probe(dev, PTR_ERR(phy_provider),
				     "failed to register PHY provider\n");

	return 0;
}

static const struct of_device_id k1_usb2_phy_of_match[] = {
	{ .compatible = "spacemit,k1-usb2-phy" },
	{ },
};
MODULE_DEVICE_TABLE(of, k1_usb2_phy_of_match);

static struct platform_driver k1_usb2_phy_driver = {
	.probe	= k1_usb2_phy_probe,
	.driver = {
		.of_match_table	= k1_usb2_phy_of_match,
		.name = "spacemit-k1-usb2-phy",
	},
};
module_platform_driver(k1_usb2_phy_driver);

MODULE_DESCRIPTION("SpacemiT K1 USB 2.0 PHY driver");
MODULE_LICENSE("GPL");

